import React from "react";
import MetricCard from "../components/MetricCard";
import { StatusBadge, UrgencyBadge, CategoryBadge } from "../components/Badges";
import { URGENCY_COLORS } from "../utils/helpers";
import { useNavigate } from "react-router-dom";

export default function VolunteerDashboard({ user, needs, assignments }) {
  const navigate = useNavigate();

  const myNeeds = needs.filter((n) => n.volunteerId === user?.id);
  const activeNeeds = myNeeds.filter((n) => n.status === "in-progress");
  const completedNeeds = myNeeds.filter((n) => n.status === "completed");
  const availableNeeds = needs.filter((n) => !n.volunteerId && n.status === "pending").slice(0, 5);

  return (
    <div>
      <div style={{ marginBottom: 24 }}>
        <h2 style={{ fontSize: 24, fontWeight: 700, color: "#1e293b" }}>Welcome, {user?.name || "Volunteer"}! 👋</h2>
        <p style={{ color: "#64748b" }}>Here's your current task overview</p>
      </div>

      <div className="grid-4" style={{ marginBottom: "1.5rem" }}>
        <MetricCard label="Active Tasks" value={activeNeeds.length} sub="in progress" color="#2563eb" />
        <MetricCard label="Completed" value={completedNeeds.length} sub="tasks finished" color="#16a34a" />
        <MetricCard label="Available" value={availableNeeds.length} sub="needs open for you" color="#d97706" />
        <MetricCard label="Impact" value={myNeeds.reduce((s, n) => s + (n.peopleAffected || 0), 0)} sub="people helped" color="#7c3aed" />
      </div>

      <div className="grid-2">
        <div className="card">
          <div className="section-title">My Active Tasks</div>
          {activeNeeds.length === 0 && (
            <div style={{ textAlign: "center", padding: "24px 0" }}>
              <div style={{ fontSize: 32, marginBottom: 8 }}>📋</div>
              <p style={{ color: "#94a3b8", fontSize: 13, marginBottom: 12 }}>No active tasks. Pick one below!</p>
              <button className="btn btn-sm btn-primary" onClick={() => navigate("/needs")}>Browse Needs</button>
            </div>
          )}
          {activeNeeds.map((n) => (
            <div
              key={n.id}
              className="need-row"
              onClick={() => navigate(`/task/${n.id}`)}
              style={{ cursor: "pointer", borderLeft: `4px solid ${URGENCY_COLORS[n.urgency] || "#94a3b8"}`, paddingLeft: 12 }}
            >
              <div style={{ flex: 1 }}>
                <div style={{ fontWeight: 600, fontSize: 14 }}>{n.title}</div>
                <div style={{ fontSize: 12, color: "#64748b", marginTop: 2 }}>{n.address || "Location on file"}</div>
                <div style={{ display: "flex", gap: 6, marginTop: 6 }}>
                  <StatusBadge status={n.status} />
                  <UrgencyBadge urgency={n.urgency} />
                </div>
              </div>
              <span style={{ fontSize: 20 }}>›</span>
            </div>
          ))}
        </div>

        <div className="card">
          <div className="section-title">Available Needs Near You</div>
          {availableNeeds.length === 0 && <p style={{ color: "#94a3b8", fontSize: 13 }}>No open needs at the moment.</p>}
          {availableNeeds.map((n) => (
            <div
              key={n.id}
              className="need-row"
              onClick={() => navigate(`/task/${n.id}`)}
              style={{ cursor: "pointer" }}
            >
              <div style={{ minWidth: 40 }}>
                <div style={{ fontSize: 16, fontWeight: 700, color: URGENCY_COLORS[n.urgency], fontFamily: "monospace" }}>{n.priorityScore}</div>
              </div>
              <div style={{ flex: 1 }}>
                <div style={{ fontWeight: 500, fontSize: 13 }}>{n.title}</div>
                <div style={{ display: "flex", gap: 4, marginTop: 3 }}>
                  <UrgencyBadge urgency={n.urgency} />
                  <CategoryBadge category={n.category} />
                </div>
              </div>
              <button className="btn btn-sm" style={{ fontSize: 11, padding: "4px 10px", background: "#dcfce7", color: "#166534", border: "1px solid #86efac" }}>
                View →
              </button>
            </div>
          ))}
          <button
            className="btn btn-outline"
            style={{ width: "100%", marginTop: 12, fontSize: 12 }}
            onClick={() => navigate("/needs")}
          >
            See all available needs
          </button>
        </div>
      </div>
    </div>
  );
}
